function combination(n, k) {
    if (k < 0 || k > n) return 0;
    if (k === 0 || k === n) return 1;

    const max = Math.max(k, n - k);
    let numerator = 1;
    for (let i = 0; i < max; i++) {
        numerator = (numerator * (n - i)) % (10**9 + 7);
    }

    let denominator = 1;
    for (let i = 1; i <= max; i++) {
        denominator = (denominator * i) % (10**9 + 7);
    }

    return (numerator * pow(denominator, 10**9 + 7 - 2, 10**9 + 7)) % (10**9 + 7);
}

function pow(base, exp, mod) {
    let result = 1;
    while (exp > 0) {
        if (exp % 2 === 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp = Math.floor(exp / 2);
    }
    return result;
}
