    for (const [y, xs] of yMap.entries()) {
        const n = xs.length;
        if (n < 2) continue;

        // Count the number of pairs of points at the same y-coordinate
        const count = n * (n - 1) / 2;
        result = (result + count) % MOD;

        // For each pair of points at the same y-coordinate, look for another y-coordinate
        for (let i = 0; i < xs.length; i++) {
            for (let j = i + 1; j < xs.length; j++) {
                const x1 = xs[i];
                const x2 = xs[j];

                // Look for another y-coordinate with points that can form a horizontal line
                for (const [otherY, otherXs] of yMap.entries()) {
                    if (otherY === y) continue;

                    // Check if there are points with x-coordinates that can form a horizontal line
                    let found = false;
                    for (const x of otherXs) {
                        if (x === x1 || x === x2) {
                            found = true;
                            break;
                        }
                    }

                    if (found) {
                        // Count the number of pairs in the other y-coordinate
                        const otherCount = otherXs.length * (otherXs.length - 1) / 2;
                        result = (result + otherCount) % MOD;
                    }
                }
            }
        }
    }

    return result;
}
